// POST /api/query/:collection
// Body: { filter: {}, projection: {}, sort: {}, limit: 50, skip: 0 }
app.post('/api/query/:collection', async (req, res) => {
  try {
    const collection = validateCollectionName(req.params.collection);

    const {
      filter = {},
      projection,
      sort,
      limit = 50,
      skip = 0
    } = req.body;

    // Validate limit and skip
    const sanitizedLimit = Math.min(Math.max(parseInt(limit, 10) || 50, 1), 1000);
    const sanitizedSkip = Math.max(parseInt(skip, 10) || 0, 0);

    // Sanitize all inputs
    const sanitizedFilter = sanitizeFilter(filter);
    const sanitizedProjection = sanitizeProjection(projection);
    const sanitizedSort = sanitizeSort(sort);

    const queryOptions = {
      limit: sanitizedLimit,
      skip: sanitizedSkip
    };

    if (sanitizedProjection) {
      queryOptions.projection = sanitizedProjection;
    }

    if (sanitizedSort) {
      queryOptions.sort = sanitizedSort;
    }

    const results = await db
      .collection(collection)
      .find(sanitizedFilter, queryOptions)
      .toArray();

    // Get total count for pagination
    const totalCount = await db
      .collection(collection)
      .countDocuments(sanitizedFilter);

    res.json({
      success: true,
      data: results,
      pagination: {
        total: totalCount,
        limit: sanitizedLimit,
        skip: sanitizedSkip,
        returned: results.length
      }
    });
  } catch (error) {
    console.error('Query error:', error.message);
    res.status(400).json({
      success: false,
      error: error.message
    });
  }
});

// GET /api/query/:collection/:id
app.get('/api/query/:collection/:id', async (req, res) => {
  try {
    const collection = validateCollectionName(req.params.collection);

    // Validate ObjectId format
    if (!ObjectId.isValid(req.params.id)) {
      return res.status(400).json({
        success: false,
        error: 'Invalid document ID format'
      });
    }

    const result = await db
      .collection(collection)
      .findOne({ _id: new ObjectId(req.params.id) });

    if (!result) {
      return res.status(404).json({
        success: false,
        error: 'Document not found'
      });
    }

    res.json({
      success: true,
      data: result
    });
  } catch (error) {
    console.error('Query error:', error.message);
    res.status(400).json({
      success: false,
      error: error.message
    });
  }
});

